{
  "name": "RevGame",
  "description": "A high-stakes trivia platform with a premium Millionaire-style aesthetic, featuring progression-based rewards, multiple game modes, and competitive leaderboards.",
  "requestFramePermissions": []
}

export enum GameMode {
  CLASSIC = 'CLASSIC',
  TIMED = 'TIMED',
  CATEGORY = 'CATEGORY',
  SURVIVAL = 'SURVIVAL'
}

export type Category = 
  | 'Mathematics'
  | 'English'
  | 'Physics'
  | 'Chemistry'
  | 'Biology'
  | 'Geography'
  | 'Basic Science'
  | 'Nigerian History'
  | 'Global Current Affairs'
  | 'Nigerian Current Affairs';

export interface Question {
  id: string;
  text: string;
  options: string[];
  correctAnswer: number; // Index 0-3
  explanation: string;
  difficulty: number; // 1-36
  category: Category;
}

export interface User {
  id: string;
  username: string;
  email: string;
  royaltyPoints: number;
  highestScore: number;
  longestStreak: number;
  favoriteCategory: Category;
  avatar: string;
  playCount: Record<Category, number>;
}

export interface GameState {
  currentQuestionIndex: number;
  score: number;
  isGameOver: boolean;
  isWon: boolean;
  timeLeft?: number;
  questions: Question[];
  streak: number;
  maxStreak: number;
  selectedOption: number | null;
  showFeedback: boolean;
}

export interface LeaderboardEntry {
  id: string;
  username: string;
  royaltyPoints: number;
  highestScore: number;
  avatar: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Question, Category } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const QUESTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    text: { type: Type.STRING },
    options: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      minItems: 4,
      maxItems: 4
    },
    correctAnswer: { type: Type.INTEGER, description: "Index 0 to 3" },
    explanation: { type: Type.STRING }
  },
  required: ["text", "options", "correctAnswer", "explanation"]
};

export const fetchQuestions = async (
  count: number,
  category?: Category,
  difficultyStart: number = 1
): Promise<Question[]> => {
  const prompt = `Generate ${count} unique, high-quality trivia questions for a game called RevGame.
  ${category ? `Category: ${category}.` : "Randomize categories from high school subjects (Math, English, Science, etc.)."}
  Difficulty progression should start at level ${difficultyStart} out of 36.
  Questions must be accurate and challenging.
  For Nigerian subjects, use authentic local context.
  Output the response as a JSON array of question objects.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: QUESTION_SCHEMA
        }
      }
    });

    const rawQuestions = JSON.parse(response.text);
    return rawQuestions.map((q: any, index: number) => ({
      ...q,
      id: Math.random().toString(36).substr(2, 9),
      difficulty: difficultyStart + index,
      category: category || "Global Current Affairs"
    }));
  } catch (error) {
    console.error("Error fetching questions:", error);
    // Fallback static questions for demo if API fails
    return [
      {
        id: "fallback-1",
        text: "What is the capital of Nigeria?",
        options: ["Lagos", "Abuja", "Kano", "Ibadan"],
        correctAnswer: 1,
        explanation: "Abuja replaced Lagos as the capital in 1991.",
        difficulty: 1,
        category: "Nigerian Current Affairs"
      }
    ];
  }
};

