import React, { useState, useEffect, useCallback } from 'react';
import { GameMode, GameState, Question, User, Category } from '../types';
import { fetchQuestions } from '../services/geminiService';
import { ICONS, GOLD_COLOR } from '../constants';

interface GameViewProps {
  mode: GameMode;
  category?: Category;
  user: User;
  onGameEnd: (stats: { score: number; streak: number; won: boolean }) => void;
  onExit: () => void;
}

const GameView: React.FC<GameViewProps> = ({ mode, category, user, onGameEnd, onExit }) => {
  const [state, setState] = useState<GameState>({
    currentQuestionIndex: 0,
    score: 0,
    isGameOver: false,
    isWon: false,
    timeLeft: mode === GameMode.TIMED ? 120 : undefined,
    questions: [],
    streak: 0,
    maxStreak: 0,
    selectedOption: null,
    showFeedback: false,
  });

  const [isLoading, setIsLoading] = useState(true);

  const loadQuestions = useCallback(async () => {
    setIsLoading(true);
    let count = 36;
    if (mode === GameMode.TIMED) count = 20; // Load 20 initial for timed
    if (mode === GameMode.SURVIVAL) count = 50; 

    const qs = await fetchQuestions(count, category);
    setState(prev => ({ ...prev, questions: qs }));
    setIsLoading(false);
  }, [mode, category]);

  useEffect(() => {
    loadQuestions();
  }, [loadQuestions]);

  useEffect(() => {
    let timer: any;
    if (mode === GameMode.TIMED && state.timeLeft !== undefined && state.timeLeft > 0 && !state.isGameOver) {
      timer = setInterval(() => {
        setState(prev => ({ 
          ...prev, 
          timeLeft: prev.timeLeft ? prev.timeLeft - 1 : 0 
        }));
      }, 1000);
    } else if (mode === GameMode.TIMED && state.timeLeft === 0) {
      endGame(false);
    }
    return () => clearInterval(timer);
  }, [state.timeLeft, state.isGameOver, mode]);

  const endGame = (won: boolean) => {
    setState(prev => ({ ...prev, isGameOver: true, isWon: won }));
    onGameEnd({ 
      score: state.score + (won ? state.questions.length * 10 : 0), 
      streak: state.maxStreak, 
      won 
    });
  };

  const handleOptionClick = (index: number) => {
    if (state.selectedOption !== null || state.isGameOver) return;

    const currentQ = state.questions[state.currentQuestionIndex];
    const isCorrect = index === currentQ.correctAnswer;

    setState(prev => {
      const newStreak = isCorrect ? prev.streak + 1 : 0;
      return {
        ...prev,
        selectedOption: index,
        showFeedback: true,
        streak: newStreak,
        maxStreak: Math.max(prev.maxStreak, newStreak),
        score: isCorrect ? prev.score + (10 * prev.difficulty) : prev.score
      };
    });

    setTimeout(() => {
      if (isCorrect) {
        if (state.currentQuestionIndex + 1 === state.questions.length) {
          if (mode === GameMode.CLASSIC) {
            endGame(true);
          } else {
            // Infinite mode support could go here by fetching more questions
            endGame(true);
          }
        } else {
          setState(prev => ({
            ...prev,
            currentQuestionIndex: prev.currentQuestionIndex + 1,
            selectedOption: null,
            showFeedback: false,
          }));
        }
      } else {
        if (mode === GameMode.SURVIVAL) {
          endGame(false);
        } else {
          // Classic/Category/Timed: Allow mistake but show feedback
          // In "Millionaire" classic, you might lose if you get it wrong. 
          // Requirements say: "selected button turns Red, and correct highlighted Green"
          // Let's allow a short delay so they can see it before ending game or moving on.
          setTimeout(() => endGame(false), 2000);
        }
      }
    }, 1500);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#050b18]">
        <div className="w-16 h-16 border-4 border-[#d4af37]/20 border-t-[#d4af37] rounded-full animate-spin mb-4"></div>
        <p className="text-[#d4af37] font-cinzel tracking-widest">PREPARING ARENA...</p>
      </div>
    );
  }

  const currentQ = state.questions[state.currentQuestionIndex];

  return (
    <div className="min-h-screen flex flex-col bg-[#050b18] text-white p-6 pb-24">
      {/* Header Info */}
      <div className="flex justify-between items-center mb-8">
        <button onClick={onExit} className="p-2 text-gray-400 hover:text-white transition-colors">
          <ICONS.X className="w-6 h-6" />
        </button>
        <div className="flex-1 flex flex-col items-center">
          <span className="text-[10px] text-[#d4af37] font-bold tracking-widest uppercase mb-1">
            {mode} Mode • {currentQ.category}
          </span>
          <div className="flex items-center gap-2">
            <ICONS.Award className="w-4 h-4 text-[#d4af37]" />
            <span className="font-cinzel text-xl gold-text-gradient">{state.score.toLocaleString()}</span>
          </div>
        </div>
        <div className="w-10">
          {mode === GameMode.TIMED && (
            <div className="w-10 h-10 rounded-full border-2 border-[#d4af37] flex items-center justify-center text-xs font-bold text-[#d4af37]">
              {state.timeLeft}
            </div>
          )}
        </div>
      </div>

      {/* Progress Tracker */}
      {mode === GameMode.CLASSIC && (
        <div className="w-full flex gap-1 mb-8">
          {Array.from({ length: 36 }).map((_, i) => (
            <div 
              key={i}
              className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
                i < state.currentQuestionIndex ? 'bg-[#d4af37]' : 
                i === state.currentQuestionIndex ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 
                'bg-slate-800'
              }`}
            />
          ))}
        </div>
      )}

      {/* Question */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-8 max-w-2xl mx-auto w-full">
        <div className="glass-card w-full p-8 rounded-2xl relative overflow-hidden border border-[#d4af37]/20 shadow-2xl">
           <div className="absolute top-0 left-0 w-1 h-full bg-[#d4af37]/40"></div>
           <h2 className="text-xl md:text-2xl font-semibold leading-relaxed text-center">
             {currentQ.text}
           </h2>
        </div>

        {/* Options */}
        <div className="grid grid-cols-1 gap-4 w-full">
          {currentQ.options.map((option, idx) => {
            let bgColor = "bg-slate-900/50";
            let borderColor = "border-slate-800";
            let textColor = "text-gray-300";

            if (state.selectedOption === idx) {
              if (idx === currentQ.correctAnswer) {
                bgColor = "bg-green-600/20";
                borderColor = "border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]";
                textColor = "text-green-400";
              } else {
                bgColor = "bg-red-600/20";
                borderColor = "border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.3)]";
                textColor = "text-red-400";
              }
            } else if (state.showFeedback && idx === currentQ.correctAnswer) {
              bgColor = "bg-green-600/20";
              borderColor = "border-green-500";
              textColor = "text-green-400";
            }

            return (
              <button
                key={idx}
                onClick={() => handleOptionClick(idx)}
                disabled={state.selectedOption !== null}
                className={`w-full group relative flex items-center p-5 rounded-xl border-2 transition-all duration-300 transform active:scale-[0.98] ${bgColor} ${borderColor} ${textColor}`}
              >
                <div className="mr-4 w-8 h-8 rounded-lg flex items-center justify-center bg-slate-800 group-hover:bg-[#d4af37] group-hover:text-slate-900 transition-colors font-bold">
                  {String.fromCharCode(65 + idx)}
                </div>
                <span className="flex-1 text-left font-medium">{option}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Win Overlay */}
      {state.isGameOver && state.isWon && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-6 bg-slate-900/95 backdrop-blur-md">
          <div className="text-center">
            <ICONS.Crown className="w-20 h-20 text-[#d4af37] mx-auto mb-6 drop-shadow-[0_0_15px_rgba(212,175,55,0.5)]" />
            <h1 className="text-5xl font-cinzel gold-text-gradient font-bold mb-4">LEGENDARY!</h1>
            <p className="text-xl text-gray-300 mb-8">You conquered all 36 levels of knowledge.</p>
            <div className="glass-card p-6 rounded-2xl border-[#d4af37] mb-8">
               <div className="text-sm text-[#d4af37] uppercase tracking-widest mb-2 font-bold">Total Score</div>
               <div className="text-4xl font-cinzel font-bold">{state.score.toLocaleString()}</div>
            </div>
            <button 
              onClick={onExit}
              className="px-12 py-4 gold-gradient text-slate-900 font-bold rounded-xl shadow-xl hover:scale-105 transition-transform"
            >
              CONTINUE JOURNEY
            </button>
          </div>
        </div>
      )}

      {/* Game Over Overlay */}
      {state.isGameOver && !state.isWon && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-6 bg-slate-900/90 backdrop-blur-md">
          <div className="text-center w-full max-w-sm">
            <ICONS.AlertCircle className="w-16 h-16 text-red-500 mx-auto mb-6" />
            <h2 className="text-3xl font-cinzel text-white font-bold mb-2">ELIMINATED</h2>
            <p className="text-gray-400 mb-8">Correct Answer: {currentQ.options[currentQ.correctAnswer]}</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
               <div className="glass-card p-4 rounded-xl">
                 <div className="text-[10px] text-gray-500 uppercase font-bold">Level</div>
                 <div className="text-xl font-cinzel">{state.currentQuestionIndex + 1}</div>
               </div>
               <div className="glass-card p-4 rounded-xl">
                 <div className="text-[10px] text-gray-500 uppercase font-bold">Points</div>
                 <div className="text-xl font-cinzel">{state.score}</div>
               </div>
            </div>

            <button 
              onClick={onExit}
              className="w-full py-4 border-2 border-[#d4af37] text-[#d4af37] font-bold rounded-xl hover:bg-[#d4af37] hover:text-slate-900 transition-all"
            >
              RETURN TO HUB
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameView;

import React, { useState } from 'react';
import { User, Category } from '../types';
import { ICONS, CATEGORIES } from '../constants';

interface ProfileViewProps {
  user: User;
  onUpdateUser: (updates: Partial<User>) => void;
}

const ProfileView: React.FC<ProfileViewProps> = ({ user, onUpdateUser }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedUsername, setEditedUsername] = useState(user.username);

  const saveProfile = () => {
    onUpdateUser({ username: editedUsername });
    setIsEditing(false);
  };

  return (
    <div className="min-h-screen bg-[#050b18] text-white p-6 pb-32">
      <h1 className="text-3xl font-cinzel gold-text-gradient font-bold mb-8">MY PROFILE</h1>

      <div className="glass-card rounded-2xl p-8 border border-yellow-500/20 mb-8 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4">
           <button 
             onClick={() => isEditing ? saveProfile() : setIsEditing(true)}
             className="text-[#d4af37] text-sm font-bold uppercase tracking-widest"
           >
             {isEditing ? 'Save' : 'Edit'}
           </button>
        </div>

        <div className="flex flex-col items-center">
          <div className="relative mb-6">
            <img 
              src={user.avatar} 
              alt="Avatar" 
              className="w-32 h-32 rounded-full border-4 border-[#d4af37] shadow-[0_0_20px_rgba(212,175,55,0.3)] object-cover"
            />
            <div className="absolute -bottom-2 -right-2 bg-[#d4af37] text-slate-900 rounded-full p-2">
               <ICONS.Crown className="w-5 h-5" />
            </div>
          </div>

          {isEditing ? (
            <input 
              value={editedUsername}
              onChange={(e) => setEditedUsername(e.target.value)}
              className="bg-slate-900 border border-[#d4af37]/50 rounded px-4 py-2 text-center text-xl font-bold focus:outline-none"
            />
          ) : (
            <h2 className="text-2xl font-bold tracking-tight">{user.username}</h2>
          )}
          <p className="text-gray-500 text-sm mt-1">{user.email}</p>
        </div>

        <div className="grid grid-cols-2 gap-4 mt-8 pt-8 border-t border-slate-800">
           <div className="text-center">
             <div className="text-[#d4af37] font-cinzel text-2xl font-bold">{user.royaltyPoints.toLocaleString()}</div>
             <div className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mt-1">Royalty Points</div>
           </div>
           <div className="text-center border-l border-slate-800">
             <div className="text-white font-cinzel text-2xl font-bold">{user.highestScore.toLocaleString()}</div>
             <div className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mt-1">High Score</div>
           </div>
        </div>
      </div>

      <div className="space-y-6">
        <h3 className="text-sm font-bold tracking-widest text-[#d4af37] uppercase">Acheivements & Stats</h3>

        <div className="space-y-4">
