import React, { useState, useEffect } from 'react';
import { User, GameMode, Category } from './types';
import { GAME_MODES, CATEGORIES } from './constants';
import Auth from './components/Auth';
import Navigation from './components/Navigation';
import GameView from './components/GameView';
import ProfileView from './components/ProfileView';
import LeaderboardView from './components/LeaderboardView';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [currentGame, setCurrentGame] = useState<{ mode: GameMode; category?: Category } | null>(null);

  // Initialize from storage
  useEffect(() => {
    const saved = localStorage.getItem('revgame_user');
    if (saved) setUser(JSON.parse(saved));
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('revgame_user', JSON.stringify(newUser));
  };

  const handleUpdateUser = (updates: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...updates };
    setUser(updatedUser);
    localStorage.setItem('revgame_user', JSON.stringify(updatedUser));
  };

  const handleGameEnd = (stats: { score: number; streak: number; won: boolean }) => {
    if (!user || !currentGame) return;

    const currentCat = currentGame.category || 'Global Current Affairs';
    const newPlayCount = { ...user.playCount };
    newPlayCount[currentCat] = (newPlayCount[currentCat] || 0) + 1;

    // Calculate most frequent category for favorite
    const favCat = Object.entries(newPlayCount).reduce((a, b) => a[1] > b[1] ? a : b)[0] as Category;

    handleUpdateUser({
      royaltyPoints: user.royaltyPoints + stats.score,
      highestScore: Math.max(user.highestScore, stats.score),
      longestStreak: Math.max(user.longestStreak, stats.streak),
      playCount: newPlayCount,
      favoriteCategory: favCat
    });

    if (stats.won) {
      window.confetti && window.confetti({
        particleCount: 200,
        spread: 70,
        origin: { y: 0.6 },
        colors: ['#d4af37', '#f9d976', '#ffffff']
      });
    }

    setCurrentGame(null);
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  if (currentGame) {
    return (
      <GameView 
        mode={currentGame.mode} 
        category={currentGame.category} 
        user={user}
        onGameEnd={handleGameEnd}
        onExit={() => setCurrentGame(null)}
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'leaderboard':
        return <LeaderboardView />;
      case 'profile':
        return <ProfileView user={user} onUpdateUser={handleUpdateUser} />;
      default:
        return (
          <div className="p-6 pb-32">
            <header className="flex justify-between items-center mb-10">
              <div>
                <h1 className="text-3xl font-cinzel gold-text-gradient font-bold">REVGAME</h1>
                <p className="text-gray-400 text-xs tracking-[0.2em] font-bold">THE ELITE TRIVIA ARENA</p>
              </div>
              <div 
                onClick={() => setActiveTab('profile')}
                className="w-12 h-12 rounded-full border-2 border-[#d4af37] p-0.5 cursor-pointer hover:scale-105 transition-transform"
              >
                <img src={user.avatar} className="w-full h-full rounded-full object-cover" alt="Profile" />
              </div>
            </header>

            <div className="mb-8">
              <h2 className="text-sm font-bold tracking-widest text-[#d4af37] uppercase mb-4">Choose Your Challenge</h2>
              <div className="grid grid-cols-1 gap-4">
                {GAME_MODES.map((mode) => (
                  <button
                    key={mode.id}
                    onClick={() => {
                      if (mode.id === GameMode.CATEGORY) {
                        // For simplicity, pick first category, ideally show a sub-menu
                        setCurrentGame({ mode: mode.id, category: CATEGORIES[0] });
                      } else {
                        setCurrentGame({ mode: mode.id });
                      }
                    }}
                    className={`group relative overflow-hidden glass-card p-6 rounded-2xl border border-yellow-500/10 flex items-center gap-6 transition-all duration-300 hover:border-[#d4af37]/50 hover:bg-slate-800/50`}
                  >
                    <div className="p-4 bg-slate-900 rounded-xl group-hover:scale-110 transition-transform">
                      {mode.icon}
                    </div>
                    <div className="flex-1 text-left">
                      <h3 className="text-lg font-bold font-cinzel group-hover:text-[#d4af37] transition-colors">{mode.title}</h3>
                      <p className="text-sm text-gray-500">{mode.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <div>
              <h2 className="text-sm font-bold tracking-widest text-[#d4af37] uppercase mb-4">Master Subjects</h2>
              <div className="grid grid-cols-2 gap-3">
                {CATEGORIES.map((cat) => (
                  <button
                    key={cat}
                    onClick={() => setCurrentGame({ mode: GameMode.CATEGORY, category: cat })}
                    className="glass-card p-4 rounded-xl text-left border border-slate-800 hover:border-[#d4af37]/30 transition-all active:scale-[0.98]"
                  >
                    <div className="text-[10px] text-gray-400 font-bold uppercase mb-1 truncate">{cat}</div>
                    <div className="text-xs font-bold text-[#d4af37]">Start Quiz</div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen relative max-w-md mx-auto bg-[#050b18] overflow-x-hidden">
      {renderContent()}
      <Navigation activeTab={activeTab} onTabChange={setActiveTab} />
    </div>
  );
};

export default App;

