import { GoogleGenAI, Type } from "@google/genai";
import { Question, Category } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const QUESTION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    text: { type: Type.STRING },
    options: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      minItems: 4,
      maxItems: 4
    },
    correctAnswer: { type: Type.INTEGER, description: "Index 0 to 3" },
    explanation: { type: Type.STRING }
  },
  required: ["text", "options", "correctAnswer", "explanation"]
};

export const fetchQuestions = async (
  count: number,
  category?: Category,
  difficultyStart: number = 1
): Promise<Question[]> => {
  // Determine if it is an academic subject or trivia
  const academicSubjects = ['Mathematics', 'English', 'Physics', 'Chemistry', 'Biology', 'Geography', 'Basic Science', 'Nigerian History', 'Global Current Affairs', 'Nigerian Current Affairs'];
  const isAcademic = category && academicSubjects.includes(category);

  const prompt = `Generate ${count} unique, high-quality trivia questions for a game called RevGame.
  Target Audience: High School students (JSS1 - SS3 context) for school subjects, or general adults for trivia.

  ${isAcademic 
    ? `Subject: ${category}. Ensure questions cover concepts typical for Nigerian and international secondary school curricula.` 
    : `Category: ${category || "General Knowledge"}. Focus on high-stakes Millionaire-style general trivia.`}

  Difficulty level: starting at ${difficultyStart}/36.
  Questions must be accurate, engaging, and have 4 clear options.
  Output the response as a JSON array of question objects.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: QUESTION_SCHEMA
        }
      }
    });

    const rawQuestions = JSON.parse(response.text);
    return rawQuestions.map((q: any, index: number) => ({
      ...q,
      id: Math.random().toString(36).substr(2, 9),
      difficulty: difficultyStart + index,
      category: category || "General Knowledge"
    }));
  } catch (error) {
    console.error("Error fetching questions:", error);
    return [
      {
        id: "fallback-1",
        text: "Which of these is a primary color?",
        options: ["Green", "Blue", "Orange", "Purple"],
        correctAnswer: 1,
        explanation: "Red, Blue, and Yellow are the traditional primary colors.",
        difficulty: 1,
        category: "General Knowledge"
      }
    ];
  }
};

