import React, { useState, useEffect, useCallback } from 'react';
import { GameMode, GameState, Question, User, Category } from '../types';
import { fetchQuestions } from '../services/geminiService';
import { ICONS, GOLD_COLOR } from '../constants';

interface GameViewProps {
  mode: GameMode;
  category?: Category;
  user: User;
  onGameEnd: (stats: { score: number; streak: number; won: boolean }) => void;
  onExit: () => void;
}

const GameView: React.FC<GameViewProps> = ({ mode, category, user, onGameEnd, onExit }) => {
  const [state, setState] = useState<GameState>({
    currentQuestionIndex: 0,
    score: 0,
    correctCount: 0,
    incorrectCount: 0,
    isGameOver: false,
    isWon: false,
    timeLeft: mode === GameMode.TIMED ? 120 : undefined,
    questions: [],
    streak: 0,
    maxStreak: 0,
    selectedOption: null,
    showFeedback: false,
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isScorePulsing, setIsScorePulsing] = useState(false);

  const loadQuestions = useCallback(async () => {
    setIsLoading(true);
    let count = 36;
    if (mode === GameMode.TIMED) count = 20;
    if (mode === GameMode.SURVIVAL) count = 50; 

    const qs = await fetchQuestions(count, category);
    setState(prev => ({ ...prev, questions: qs }));
    setIsLoading(false);
  }, [mode, category]);

  useEffect(() => {
    loadQuestions();
  }, [loadQuestions]);

  useEffect(() => {
    let timer: any;
    if (mode === GameMode.TIMED && state.timeLeft !== undefined && state.timeLeft > 0 && !state.isGameOver) {
      timer = setInterval(() => {
        setState(prev => ({ 
          ...prev, 
          timeLeft: prev.timeLeft ? prev.timeLeft - 1 : 0 
        }));
      }, 1000);
    } else if (mode === GameMode.TIMED && state.timeLeft === 0) {
      endGame();
    }
    return () => clearInterval(timer);
  }, [state.timeLeft, state.isGameOver, mode]);

  const endGame = () => {
    // Game is "Won" if they reach the end, regardless of wrong answers,
    // though we might measure "Winning" differently in the future.
    setState(prev => ({ ...prev, isGameOver: true, isWon: true }));
    onGameEnd({ 
      score: state.score, 
      streak: state.maxStreak, 
      won: state.incorrectCount === 0 && state.questions.length > 0 
    });
  };

  const handleOptionClick = (index: number) => {
    if (state.selectedOption !== null || state.isGameOver) return;

    const currentQ = state.questions[state.currentQuestionIndex];
    const isCorrect = index === currentQ.correctAnswer;

    if (isCorrect) {
      setIsScorePulsing(true);
      setTimeout(() => setIsScorePulsing(false), 600);
    }

    setState(prev => {
      const newStreak = isCorrect ? prev.streak + 1 : 0;
      return {
        ...prev,
        selectedOption: index,
        showFeedback: true,
        streak: newStreak,
        maxStreak: Math.max(prev.maxStreak, newStreak),
        correctCount: isCorrect ? prev.correctCount + 1 : prev.correctCount,
        incorrectCount: !isCorrect ? prev.incorrectCount + 1 : prev.incorrectCount,
        score: isCorrect ? prev.score + (10 * prev.currentQuestionIndex + 10) : prev.score
      };
    });

    setTimeout(() => {
      if (state.currentQuestionIndex + 1 === state.questions.length) {
        endGame();
      } else {
        setState(prev => ({
          ...prev,
          currentQuestionIndex: prev.currentQuestionIndex + 1,
          selectedOption: null,
          showFeedback: false,
        }));
      }
    }, 1500);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#050b18]">
        <div className="w-16 h-16 border-4 border-[#d4af37]/20 border-t-[#d4af37] rounded-full animate-spin mb-4"></div>
        <p className="text-[#d4af37] font-cinzel tracking-widest animate-pulse">PREPARING ARENA...</p>
      </div>
    );
  }

  const currentQ = state.questions[state.currentQuestionIndex];

  return (
    <div className="min-h-screen flex flex-col bg-[#050b18] text-white p-6 pb-24">
      {/* Header Info */}
      <div className="flex justify-between items-center mb-8">
        <button 
          onClick={onExit} 
          className="group flex items-center gap-2 px-3 py-1.5 rounded-full border border-slate-800 hover:border-red-500/50 hover:bg-red-500/10 transition-all text-xs font-bold text-gray-400 hover:text-red-400"
        >
          <ICONS.X className="w-4 h-4" />
          EXIT
        </button>
        <div className="flex-1 flex flex-col items-center">
          <span className="text-[10px] text-[#d4af37] font-bold tracking-widest uppercase mb-1">
            {mode} Mode • {currentQ.category}
          </span>
          <div className={`flex items-center gap-2 transition-transform duration-300 ${isScorePulsing ? 'scale-125' : 'scale-100'}`}>
            <ICONS.Award className="w-4 h-4 text-[#d4af37]" />
            <span className="font-cinzel text-xl gold-text-gradient">{state.score.toLocaleString()}</span>
          </div>
        </div>
        <div className="w-10">
          {mode === GameMode.TIMED && (
            <div className={`w-10 h-10 rounded-full border-2 flex items-center justify-center text-xs font-bold transition-colors ${state.timeLeft && state.timeLeft < 10 ? 'border-red-500 text-red-500 animate-pulse' : 'border-[#d4af37] text-[#d4af37]'}`}>
              {state.timeLeft}
            </div>
          )}
        </div>
      </div>

      {/* Progress Tracker */}
      <div className="w-full flex gap-1 mb-8">
        {Array.from({ length: Math.min(state.questions.length, 36) }).map((_, i) => (
          <div 
            key={i}
            className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
              i < state.currentQuestionIndex ? 'bg-[#d4af37]' : 
              i === state.currentQuestionIndex ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 
              'bg-slate-800'
            }`}
          />
        ))}
      </div>

      {/* Question */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-8 max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
        <div className="glass-card w-full p-8 rounded-2xl relative overflow-hidden border border-[#d4af37]/20 shadow-2xl min-h-[160px] flex items-center justify-center">
           <div className="absolute top-0 left-0 w-1 h-full bg-[#d4af37]/40"></div>
           <h2 className="text-xl md:text-2xl font-semibold leading-relaxed text-center">
             {currentQ.text}
           </h2>
        </div>

        {/* Options */}
        <div className="grid grid-cols-1 gap-4 w-full">
          {currentQ.options.map((option, idx) => {
            let bgColor = "bg-slate-900/50";
            let borderColor = "border-slate-800";
            let textColor = "text-gray-300";

            if (state.selectedOption === idx) {
              if (idx === currentQ.correctAnswer) {
                bgColor = "bg-green-600/20";
                borderColor = "border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]";
                textColor = "text-green-400";
              } else {
                bgColor = "bg-red-600/20";
                borderColor = "border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.3)]";
                textColor = "text-red-400";
              }
            } else if (state.showFeedback && idx === currentQ.correctAnswer) {
              bgColor = "bg-green-600/20";
              borderColor = "border-green-500";
              textColor = "text-green-400";
            }

            return (
              <button
                key={idx}
                onClick={() => handleOptionClick(idx)}
                disabled={state.selectedOption !== null}
                className={`w-full group relative flex items-center p-5 rounded-xl border-2 transition-all duration-300 transform active:scale-[0.98] ${bgColor} ${borderColor} ${textColor}`}
              >
                <div className={`mr-4 w-8 h-8 rounded-lg flex items-center justify-center bg-slate-800 transition-colors font-bold ${state.selectedOption === null ? 'group-hover:bg-[#d4af37] group-hover:text-slate-900' : ''}`}>
                  {String.fromCharCode(65 + idx)}
                </div>
                <span className="flex-1 text-left font-medium">{option}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Summary Overlay (Replaces Win/Eliminated) */}
      {state.isGameOver && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-6 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-500">
          <div className="text-center w-full max-w-sm">
            <ICONS.Trophy className="w-20 h-20 text-[#d4af37] mx-auto mb-6 drop-shadow-[0_0_15px_rgba(212,175,55,0.5)]" />
            <h1 className="text-4xl font-cinzel gold-text-gradient font-bold mb-2">SESSION ENDED</h1>
            <p className="text-gray-400 mb-8 uppercase tracking-widest text-xs font-bold">Arena performance summary</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
               <div className="glass-card p-4 rounded-xl border-green-500/30">
                 <div className="text-[10px] text-green-500/70 uppercase font-bold">Correct</div>
                 <div className="text-2xl font-cinzel text-green-400">{state.correctCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl border-red-500/30">
                 <div className="text-[10px] text-red-500/70 uppercase font-bold">Incorrect</div>
                 <div className="text-2xl font-cinzel text-red-400">{state.incorrectCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl col-span-2 border-[#d4af37]/30">
                 <div className="text-[10px] text-[#d4af37]/70 uppercase font-bold">Final Accumulated Score</div>
                 <div className="text-3xl font-cinzel gold-text-gradient font-bold">{state.score.toLocaleString()}</div>
               </div>
            </div>

            <button 
              onClick={onExit}
              className="w-full py-4 gold-gradient text-slate-900 font-bold rounded-xl shadow-xl hover:scale-105 transition-all transform active:scale-95"
            >
              CONTINUE JOURNEY
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameView;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { CATEGORIES } from '../constants';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(false);
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [hasAccounts, setHasAccounts] = useState(false);

  useEffect(() => {
    const users = JSON.parse(localStorage.getItem('revgame_users') || '[]');
    setHasAccounts(users.length > 0);
    // Explicitly force signup if no accounts are present
    if (users.length === 0) {
      setIsLogin(false);
    }
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const users = JSON.parse(localStorage.getItem('revgame_users') || '[]');

    if (isLogin) {
      const foundUser = users.find((u: any) => u.email === email && u.password === password);
      if (foundUser) {
        onLogin(foundUser);
      } else {
        setError('Invalid credentials. Check your email or password.');
      }
    } else {
      if (users.some((u: any) => u.email === email)) {
        setError('An account with this email already exists.');
        return;
      }

      const newUser: User & { password: string } = {
        id: Math.random().toString(36).substr(2, 9),
        username: username || 'EliteTrv101',
        email: email,
        password: password,
        royaltyPoints: 0,
        highestScore: 0,
        longestStreak: 0,
        favoriteCategory: CATEGORIES[0],
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${username || 'random'}`,
        playCount: CATEGORIES.reduce((acc, cat) => ({ ...acc, [cat]: 0 }), {} as Record<string, number>)
      };

      users.push(newUser);
      localStorage.setItem('revgame_users', JSON.stringify(users));
      onLogin(newUser);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-[#050b18]">
      <div className="w-full max-w-md glass-card p-8 rounded-2xl shadow-2xl border border-yellow-500/20">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-cinzel gold-text-gradient font-bold mb-2">REVGAME</h1>
          <p className="text-gray-400">Step into the arena of knowledge</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-500/10 border border-red-500/50 rounded-lg text-red-400 text-sm text-center animate-bounce">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {!isLogin && (
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1">Username</label>
              <input
                type="text"
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-slate-900 border border-slate-800 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#d4af37] transition-colors"
                placeholder="TheWiseOne"
              />
            </div>
          )}
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Email</label>
            <input
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-slate-900 border border-slate-800 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#d4af37] transition-colors"
              placeholder="you@example.com"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-400 mb-1">Password</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full bg-slate-900 border border-slate-800 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-[#d4af37] transition-colors"
              placeholder="••••••••"
            />
          </div>

          <button
            type="submit"
            className="w-full gold-gradient text-slate-900 font-bold py-4 rounded-lg shadow-lg hover:opacity-90 transition-all transform active:scale-[0.98]"
          >
            {isLogin ? 'LOG IN' : 'CREATE ACCOUNT'}
          </button>
        </form>

        {hasAccounts && (
          <div className="mt-8 text-center">
            <button
              onClick={() => setIsLogin(!isLogin)}
              className="text-[#d4af37] text-sm hover:underline"
            >
              {isLogin ? "Don't have an account? Sign Up" : "Already have an account? Log In"}
            </button>
          </div>
        )}

        {!hasAccounts && (
          <div className="mt-8 text-center">
            <p className="text-gray-500 text-xs italic">Registration required for first-time access.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { User, GameMode, Category } from './types';
import { GAME_MODES, TRIVIA_CATEGORIES, ACADEMIC_SUBJECTS } from './constants';
import Auth from './components/Auth';
import Navigation from './components/Navigation';
import GameView from './components/GameView';
import ProfileView from './components/ProfileView';
import LeaderboardView from './components/LeaderboardView';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [currentGame, setCurrentGame] = useState<{ mode: GameMode; category?: Category } | null>(null);
  const [showAcademicMenu, setShowAcademicMenu] = useState(false);
  const [showSpecialistMenu, setShowSpecialistMenu] = useState(false);

  // Initialize from storage
  useEffect(() => {
    const saved = localStorage.getItem('revgame_active_user');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setUser(parsed);
      } catch (e) {
        console.error("Failed to parse saved user", e);
      }
    }
  }, []);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem('revgame_active_user', JSON.stringify(newUser));
  };

  const handleLogout = () => {
    // Before logging out, we could perform one final sync if needed, 
    // but handleUpdateUser ensures everything is saved immediately.
    setUser(null);
    localStorage.removeItem('revgame_active_user');
    setActiveTab('home');
  };

  const handleUpdateUser = (updates: Partial<User>) => {
    if (!user) return;

    // Create the updated state
    const updatedUser = { ...user, ...updates };
    setUser(updatedUser);

    // Persist session
    localStorage.setItem('revgame_active_user', JSON.stringify(updatedUser));

    // Update global user repository
    const usersJson = localStorage.getItem('revgame_users');
    const users = JSON.parse(usersJson || '[]');
    const updatedUsers = users.map((u: any) => u.id === user.id ? { ...u, ...updates } : u);
    localStorage.setItem('revgame_users', JSON.stringify(updatedUsers));
  };

  const handleGameEnd = (stats: { score: number; streak: number; won: boolean }) => {
    if (!user || !currentGame) return;

    const currentCat = currentGame.category || 'General Knowledge';
    const newPlayCount = { ...user.playCount };
    newPlayCount[currentCat] = (newPlayCount[currentCat] || 0) + 1;

    // Recalculate favorite category
    const favCat = Object.entries(newPlayCount).reduce((a, b) => a[1] > b[1] ? a : b, [currentCat, 0])[0] as Category;

    handleUpdateUser({
      royaltyPoints: user.royaltyPoints + stats.score,
      highestScore: Math.max(user.highestScore, stats.score),
      longestStreak: Math.max(user.longestStreak, stats.streak),
      playCount: newPlayCount,
      favoriteCategory: favCat
    });

    if (stats.won) {
      const win = window as any;
      if (win.confetti) {
        win.confetti({
          particleCount: 200,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#d4af37', '#f9d976', '#ffffff']
        });
      }
    }

    setCurrentGame(null);
    setShowAcademicMenu(false);
    setShowSpecialistMenu(false);
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  if (currentGame) {
    return (
      <GameView 
        mode={currentGame.mode} 
        category={currentGame.category} 
        user={user}
        onGameEnd={handleGameEnd}
        onExit={(stats) => {
          // If the player exits early, still save their current score and streak
          if (stats && stats.score > 0) {
            handleGameEnd({ ...stats, won: false });
          } else {
            setCurrentGame(null);
          }
        }}
      />
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'leaderboard':
        return <LeaderboardView />;
      case 'profile':
        return <ProfileView user={user} onUpdateUser={handleUpdateUser} onLogout={handleLogout} />;
      default:
        return (
          <div className="p-6 pb-32 animate-in fade-in duration-500">
            <header className="flex justify-between items-center mb-10">
              <div>
                <h1 className="text-3xl font-cinzel gold-text-gradient font-bold">REVGAME</h1>
                <p className="text-gray-400 text-xs tracking-[0.2em] font-bold">THE ELITE TRIVIA ARENA</p>
              </div>
              <div 
                onClick={() => setActiveTab('profile')}
                className="w-12 h-12 rounded-full border-2 border-[#d4af37] p-0.5 cursor-pointer hover:scale-110 transition-transform active:scale-95 overflow-hidden shadow-lg shadow-yellow-500/10"
              >
                <img src={user.avatar} className="w-full h-full rounded-full object-cover bg-slate-800" alt="Profile" />
              </div>
            </header>

            <div className="mb-8">
              <h2 className="text-sm font-bold tracking-widest text-[#d4af37] uppercase mb-4">Core Challenges</h2>
              <div className="grid grid-cols-1 gap-4">
                {GAME_MODES.slice(0, 4).map((mode) => (
                  <button
                    key={mode.id}
                    onClick={() => {
                      if (mode.id === GameMode.CATEGORY) {
                        setShowSpecialistMenu(!showSpecialistMenu);
                        setShowAcademicMenu(false);
                      } else {
                        setCurrentGame({ mode: mode.id, category: 'General Knowledge' });
                      }
                    }}
                    className={`group relative overflow-hidden glass-card p-6 rounded-2xl border border-yellow-500/10 flex items-center gap-6 transition-all duration-300 hover:border-[#d4af37]/50 hover:bg-slate-800/50 active:scale-[0.98] ${showSpecialistMenu && mode.id === GameMode.CATEGORY ? 'border-[#d4af37]/50 bg-slate-800/50' : ''}`}
                  >
                    <div className="p-4 bg-slate-900 rounded-xl group-hover:scale-110 transition-transform border border-slate-800">
                      {mode.icon}
                    </div>
                    <div className="flex-1 text-left">
                      <h3 className="text-lg font-bold font-cinzel group-hover:text-[#d4af37] transition-colors">{mode.title}</h3>
                      <p className="text-sm text-gray-500">{mode.description}</p>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            {showSpecialistMenu && (
              <div className="mb-8 p-4 bg-slate-900/50 rounded-2xl border border-[#d4af37]/30 animate-in slide-in-from-top-4">
                <div className="flex justify-between items-center mb-3">
                  <h3 className="text-xs font-bold text-gray-400 uppercase">Choose Trivia Niche</h3>
                  <button onClick={() => setShowSpecialistMenu(false)} className="text-[10px] text-gray-500 hover:text-[#d4af37]">Close</button>
                </div>
                <div className="grid grid-cols-2 gap-2">
                  {TRIVIA_CATEGORIES.map(cat => (
                    <button 
                      key={cat}
                      onClick={() => setCurrentGame({ mode: GameMode.CATEGORY, category: cat })}
                      className="p-3 text-xs font-bold text-white bg-slate-800 rounded-lg hover:bg-[#d4af37] hover:text-[#050b18] transition-all truncate border border-slate-700 hover:border-[#d4af37]"
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="mb-8">
              <h2 className="text-sm font-bold tracking-widest text-[#d4af37] uppercase mb-4">Academic Excellence</h2>
              <button
                onClick={() => {
                  setShowAcademicMenu(!showAcademicMenu);
                  setShowSpecialistMenu(false);
                }}
                className={`group w-full relative overflow-hidden glass-card p-6 rounded-2xl border border-purple-500/30 flex items-center gap-6 transition-all duration-300 hover:border-purple-400/50 hover:bg-slate-800/50 active:scale-[0.98] ${showAcademicMenu ? 'bg-slate-800/80 border-purple-400' : ''}`}
              >
                <div className="p-4 bg-slate-900 rounded-xl group-hover:scale-110 transition-transform border border-slate-800">
                  {GAME_MODES[4].icon}
                </div>
                <div className="flex-1 text-left">
                  <div className="flex items-center gap-2">
                    <h3 className="text-lg font-bold font-cinzel group-hover:text-purple-400 transition-colors">{GAME_MODES[4].title}</h3>
                    <div className="bg-purple-500/20 text-purple-400 text-[8px] font-bold px-1.5 py-0.5 rounded uppercase border border-purple-500/30">New</div>
                  </div>
                  <p className="text-sm text-gray-500">{GAME_MODES[4].description}</p>
                </div>
              </button>
            </div>

            {showAcademicMenu && (
              <div className="grid grid-cols-2 gap-3 animate-in slide-in-from-top-4 mb-10">
                {ACADEMIC_SUBJECTS.map((cat) => (
                  <button
                    key={cat}
                    onClick={() => setCurrentGame({ mode: GameMode.ACADEMIC, category: cat })}
                    className="glass-card p-4 rounded-xl text-left border border-slate-800 hover:border-purple-500/50 transition-all active:scale-[0.98]"
                  >
                    <div className="text-[10px] text-gray-400 font-bold uppercase mb-1 truncate">{cat}</div>
                    <div className="text-xs font-bold text-purple-400">Challenge Now</div>
                  </button>
                ))}
              </div>
            )}
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen relative max-w-md mx-auto bg-[#050b18] overflow-x-hidden border-x border-slate-800 shadow-[0_0_100px_rgba(212,175,55,0.05)]">
      {renderContent()}
      <Navigation activeTab={activeTab} onTabChange={(tab) => {
        setActiveTab(tab);
        setShowAcademicMenu(false);
        setShowSpecialistMenu(false);
      }} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { GameMode, GameState, Question, User, Category } from '../types';
import { fetchQuestions } from '../services/geminiService';
import { ICONS, GOLD_COLOR } from '../constants';

interface GameViewProps {
  mode: GameMode;
  category?: Category;
  user: User;
  onGameEnd: (stats: { score: number; streak: number; won: boolean }) => void;
  onExit: (stats?: { score: number; streak: number }) => void;
}

const GameView: React.FC<GameViewProps> = ({ mode, category, user, onGameEnd, onExit }) => {
  const [state, setState] = useState<GameState>({
    currentQuestionIndex: 0,
    score: 0,
    correctCount: 0,
    incorrectCount: 0,
    isGameOver: false,
    isWon: false,
    timeLeft: mode === GameMode.TIMED ? 120 : undefined,
    questions: [],
    streak: 0,
    maxStreak: 0,
    selectedOption: null,
    showFeedback: false,
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isScorePulsing, setIsScorePulsing] = useState(false);

  const loadQuestions = useCallback(async () => {
    setIsLoading(true);
    let count = 36;
    if (mode === GameMode.TIMED) count = 20;
    if (mode === GameMode.SURVIVAL) count = 50; 

    const qs = await fetchQuestions(count, category);
    setState(prev => ({ ...prev, questions: qs }));
    setIsLoading(false);
  }, [mode, category]);

  useEffect(() => {
    loadQuestions();
  }, [loadQuestions]);

  useEffect(() => {
    let timer: any;
    if (mode === GameMode.TIMED && state.timeLeft !== undefined && state.timeLeft > 0 && !state.isGameOver) {
      timer = setInterval(() => {
        setState(prev => ({ 
          ...prev, 
          timeLeft: prev.timeLeft ? prev.timeLeft - 1 : 0 
        }));
      }, 1000);
    } else if (mode === GameMode.TIMED && state.timeLeft === 0) {
      endGame();
    }
    return () => clearInterval(timer);
  }, [state.timeLeft, state.isGameOver, mode]);

  const endGame = () => {
    setState(prev => ({ ...prev, isGameOver: true, isWon: true }));
    onGameEnd({ 
      score: state.score, 
      streak: state.maxStreak, 
      won: state.incorrectCount === 0 && state.questions.length > 0 
    });
  };

  const handleOptionClick = (index: number) => {
    if (state.selectedOption !== null || state.isGameOver) return;

    const currentQ = state.questions[state.currentQuestionIndex];
    const isCorrect = index === currentQ.correctAnswer;

    if (isCorrect) {
      setIsScorePulsing(true);
      setTimeout(() => setIsScorePulsing(false), 600);
    }

    setState(prev => {
      const newStreak = isCorrect ? prev.streak + 1 : 0;
      return {
        ...prev,
        selectedOption: index,
        showFeedback: true,
        streak: newStreak,
        maxStreak: Math.max(prev.maxStreak, newStreak),
        correctCount: isCorrect ? prev.correctCount + 1 : prev.correctCount,
        incorrectCount: !isCorrect ? prev.incorrectCount + 1 : prev.incorrectCount,
        score: isCorrect ? prev.score + (10 * prev.currentQuestionIndex + 10) : prev.score
      };
    });

    setTimeout(() => {
      if (state.currentQuestionIndex + 1 === state.questions.length) {
        endGame();
      } else {
        setState(prev => ({
          ...prev,
          currentQuestionIndex: prev.currentQuestionIndex + 1,
          selectedOption: null,
          showFeedback: false,
        }));
      }
    }, 1500);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#050b18]">
        <div className="w-16 h-16 border-4 border-[#d4af37]/20 border-t-[#d4af37] rounded-full animate-spin mb-4"></div>
        <p className="text-[#d4af37] font-cinzel tracking-widest animate-pulse">PREPARING ARENA...</p>
      </div>
    );
  }

  const currentQ = state.questions[state.currentQuestionIndex];

  return (
    <div className="min-h-screen flex flex-col bg-[#050b18] text-white p-6 pb-24">
      {/* Header Info */}
      <div className="flex justify-between items-center mb-8">
        <button 
          onClick={() => onExit({ score: state.score, streak: state.maxStreak })} 
          className="group flex items-center gap-2 px-3 py-1.5 rounded-full border border-slate-800 hover:border-[#d4af37]/50 hover:bg-slate-800/80 transition-all text-xs font-bold text-gray-400 hover:text-[#d4af37]"
        >
          <ICONS.X className="w-4 h-4" />
          SAVE & EXIT
        </button>
        <div className="flex-1 flex flex-col items-center">
          <span className="text-[10px] text-[#d4af37] font-bold tracking-widest uppercase mb-1">
            {mode} Mode • {currentQ.category}
          </span>
          <div className={`flex items-center gap-2 transition-transform duration-300 ${isScorePulsing ? 'scale-125' : 'scale-100'}`}>
            <ICONS.Award className="w-4 h-4 text-[#d4af37]" />
            <span className="font-cinzel text-xl gold-text-gradient">{state.score.toLocaleString()}</span>
          </div>
        </div>
        <div className="w-10">
          {mode === GameMode.TIMED && (
            <div className={`w-10 h-10 rounded-full border-2 flex items-center justify-center text-xs font-bold transition-colors ${state.timeLeft && state.timeLeft < 10 ? 'border-red-500 text-red-500 animate-pulse' : 'border-[#d4af37] text-[#d4af37]'}`}>
              {state.timeLeft}
            </div>
          )}
        </div>
      </div>

      {/* Progress Tracker */}
      <div className="w-full flex gap-1 mb-8">
        {Array.from({ length: Math.min(state.questions.length, 36) }).map((_, i) => (
          <div 
            key={i}
            className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
              i < state.currentQuestionIndex ? 'bg-[#d4af37]' : 
              i === state.currentQuestionIndex ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 
              'bg-slate-800'
            }`}
          />
        ))}
      </div>

      {/* Question */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-8 max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
        <div className="glass-card w-full p-8 rounded-2xl relative overflow-hidden border border-[#d4af37]/20 shadow-2xl min-h-[160px] flex items-center justify-center">
           <div className="absolute top-0 left-0 w-1 h-full bg-[#d4af37]/40"></div>
           <h2 className="text-xl md:text-2xl font-semibold leading-relaxed text-center">
             {currentQ.text}
           </h2>
        </div>

        {/* Options */}
        <div className="grid grid-cols-1 gap-4 w-full">
          {currentQ.options.map((option, idx) => {
            let bgColor = "bg-slate-900/50";
            let borderColor = "border-slate-800";
            let textColor = "text-gray-300";

            if (state.selectedOption === idx) {
              if (idx === currentQ.correctAnswer) {
                bgColor = "bg-green-600/20";
                borderColor = "border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]";
                textColor = "text-green-400";
              } else {
                bgColor = "bg-red-600/20";
                borderColor = "border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.3)]";
                textColor = "text-red-400";
              }
            } else if (state.showFeedback && idx === currentQ.correctAnswer) {
              bgColor = "bg-green-600/20";
              borderColor = "border-green-500";
              textColor = "text-green-400";
            }

            return (
              <button
                key={idx}
                onClick={() => handleOptionClick(idx)}
                disabled={state.selectedOption !== null}
                className={`w-full group relative flex items-center p-5 rounded-xl border-2 transition-all duration-300 transform active:scale-[0.98] ${bgColor} ${borderColor} ${textColor}`}
              >
                <div className={`mr-4 w-8 h-8 rounded-lg flex items-center justify-center bg-slate-800 transition-colors font-bold ${state.selectedOption === null ? 'group-hover:bg-[#d4af37] group-hover:text-slate-900' : ''}`}>
                  {String.fromCharCode(65 + idx)}
                </div>
                <span className="flex-1 text-left font-medium">{option}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Summary Overlay */}
      {state.isGameOver && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-6 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-500">
          <div className="text-center w-full max-w-sm">
            <ICONS.Trophy className="w-20 h-20 text-[#d4af37] mx-auto mb-6 drop-shadow-[0_0_15px_rgba(212,175,55,0.5)]" />
            <h1 className="text-4xl font-cinzel gold-text-gradient font-bold mb-2">SESSION ENDED</h1>
            <p className="text-gray-400 mb-8 uppercase tracking-widest text-xs font-bold">Arena performance summary</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
               <div className="glass-card p-4 rounded-xl border-green-500/30">
                 <div className="text-[10px] text-green-500/70 uppercase font-bold">Correct</div>
                 <div className="text-2xl font-cinzel text-green-400">{state.correctCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl border-red-500/30">
                 <div className="text-[10px] text-red-500/70 uppercase font-bold">Incorrect</div>
                 <div className="text-2xl font-cinzel text-red-400">{state.incorrectCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl col-span-2 border-[#d4af37]/30">
                 <div className="text-[10px] text-[#d4af37]/70 uppercase font-bold">Final Accumulated Score</div>
                 <div className="text-3xl font-cinzel gold-text-gradient font-bold">{state.score.toLocaleString()}</div>
               </div>
            </div>

            <button 
              onClick={() => onExit({ score: state.score, streak: state.maxStreak })}
              className="w-full py-4 gold-gradient text-slate-900 font-bold rounded-xl shadow-xl hover:scale-105 transition-all transform active:scale-95"
            >
              CONTINUE JOURNEY
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameView;

{
  "name": "revgame",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "@google/genai": "^1.37.0",
    "lucide-react": "^0.462.0",
    "react": "^19.0.0",
    "react-dom": "^19.0.0"
  },
  "devDependencies": {
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@vitejs/plugin-react": "^4.3.4",
    "typescript": "~5.6.2",
    "vite": "^6.0.1"
  }
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    'process.env.API_KEY': JSON.stringify(process.env.API_KEY)
  }
});

import React, { useState, useEffect, useCallback } from 'react';
import { GameMode, GameState, Question, User, Category } from '../types';
import { fetchQuestions } from '../services/geminiService';
import { ICONS, GOLD_COLOR } from '../constants';

interface GameViewProps {
  mode: GameMode;
  category?: Category;
  user: User;
  onGameEnd: (stats: { score: number; streak: number; won: boolean }) => void;
  onExit: (stats?: { score: number; streak: number }) => void;
}

const GameView: React.FC<GameViewProps> = ({ mode, category, user, onGameEnd, onExit }) => {
  const [state, setState] = useState<GameState>({
    currentQuestionIndex: 0,
    score: 0,
    correctCount: 0,
    incorrectCount: 0,
    isGameOver: false,
    isWon: false,
    timeLeft: mode === GameMode.TIMED ? 120 : undefined,
    questions: [],
    streak: 0,
    maxStreak: 0,
    selectedOption: null,
    showFeedback: false,
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isScorePulsing, setIsScorePulsing] = useState(false);

  const loadQuestions = useCallback(async () => {
    setIsLoading(true);
    let count = 36;
    if (mode === GameMode.TIMED) count = 20;
    if (mode === GameMode.SURVIVAL) count = 50; 

    const qs = await fetchQuestions(count, category);
    setState(prev => ({ ...prev, questions: qs }));
    setIsLoading(false);
  }, [mode, category]);

  useEffect(() => {
    loadQuestions();
  }, [loadQuestions]);

  useEffect(() => {
    let timer: any;
    if (mode === GameMode.TIMED && state.timeLeft !== undefined && state.timeLeft > 0 && !state.isGameOver) {
      timer = setInterval(() => {
        setState(prev => ({ 
          ...prev, 
          timeLeft: prev.timeLeft ? prev.timeLeft - 1 : 0 
        }));
      }, 1000);
    } else if (mode === GameMode.TIMED && state.timeLeft === 0) {
      endGame();
    }
    return () => clearInterval(timer);
  }, [state.timeLeft, state.isGameOver, mode]);

  const endGame = () => {
    setState(prev => ({ ...prev, isGameOver: true, isWon: true }));
    onGameEnd({ 
      score: state.score, 
      streak: state.maxStreak, 
      won: state.incorrectCount === 0 && state.questions.length > 0 
    });
  };

  const handleOptionClick = (index: number) => {
    if (state.selectedOption !== null || state.isGameOver) return;

    const currentQ = state.questions[state.currentQuestionIndex];
    const isCorrect = index === currentQ.correctAnswer;

    if (isCorrect) {
      setIsScorePulsing(true);
      setTimeout(() => setIsScorePulsing(false), 600);
    }

    setState(prev => {
      const newStreak = isCorrect ? prev.streak + 1 : 0;
      return {
        ...prev,
        selectedOption: index,
        showFeedback: true,
        streak: newStreak,
        maxStreak: Math.max(prev.maxStreak, newStreak),
        correctCount: isCorrect ? prev.correctCount + 1 : prev.correctCount,
        incorrectCount: !isCorrect ? prev.incorrectCount + 1 : prev.incorrectCount,
        score: isCorrect ? prev.score + (10 * prev.currentQuestionIndex + 10) : prev.score
      };
    });

    setTimeout(() => {
      if (state.currentQuestionIndex + 1 === state.questions.length) {
        endGame();
      } else {
        setState(prev => ({
          ...prev,
          currentQuestionIndex: prev.currentQuestionIndex + 1,
          selectedOption: null,
          showFeedback: false,
        }));
      }
    }, 1500);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-[#050b18]">
        <div className="w-16 h-16 border-4 border-[#d4af37]/20 border-t-[#d4af37] rounded-full animate-spin mb-4"></div>
        <p className="text-[#d4af37] font-cinzel tracking-widest animate-pulse">PREPARING ARENA...</p>
      </div>
    );
  }

  const currentQ = state.questions[state.currentQuestionIndex];

  return (
    <div className="min-h-screen flex flex-col bg-[#050b18] text-white p-6 pb-24">
      {/* Header Info */}
      <div className="flex justify-between items-center mb-8">
        <button 
          onClick={() => onExit({ score: state.score, streak: state.maxStreak })} 
          className="group flex items-center gap-2 px-3 py-1.5 rounded-full border border-slate-800 hover:border-[#d4af37]/50 hover:bg-slate-800/80 transition-all text-xs font-bold text-gray-400 hover:text-[#d4af37]"
        >
          <ICONS.X className="w-4 h-4" />
          SAVE & EXIT
        </button>
        <div className="flex-1 flex flex-col items-center">
          <span className="text-[10px] text-[#d4af37] font-bold tracking-widest uppercase mb-1">
            {mode} Mode • {currentQ.category}
          </span>
          <div className="flex items-center gap-4">
            <div className={`flex items-center gap-2 transition-transform duration-300 ${isScorePulsing ? 'scale-110' : 'scale-100'}`}>
              <ICONS.Award className="w-4 h-4 text-[#d4af37]" />
              <span className="font-cinzel text-xl gold-text-gradient">{state.score.toLocaleString()}</span>
            </div>
            {state.streak > 0 && (
              <div className="flex items-center gap-1.5 animate-in slide-in-from-right-2 fade-in">
                <ICONS.Zap className="w-4 h-4 text-amber-400 fill-amber-400/20" />
                <span className="text-sm font-bold text-amber-400">{state.streak}</span>
              </div>
            )}
          </div>
        </div>
        <div className="w-10">
          {mode === GameMode.TIMED && (
            <div className={`w-10 h-10 rounded-full border-2 flex items-center justify-center text-xs font-bold transition-colors ${state.timeLeft && state.timeLeft < 10 ? 'border-red-500 text-red-500 animate-pulse' : 'border-[#d4af37] text-[#d4af37]'}`}>
              {state.timeLeft}
            </div>
          )}
        </div>
      </div>

      {/* Progress Tracker */}
      <div className="w-full flex gap-1 mb-8">
        {Array.from({ length: Math.min(state.questions.length, 36) }).map((_, i) => (
          <div 
            key={i}
            className={`h-1.5 flex-1 rounded-full transition-all duration-300 ${
              i < state.currentQuestionIndex ? 'bg-[#d4af37]' : 
              i === state.currentQuestionIndex ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 
              'bg-slate-800'
            }`}
          />
        ))}
      </div>

      {/* Question */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-8 max-w-2xl mx-auto w-full animate-in fade-in zoom-in duration-300">
        <div className="glass-card w-full p-8 rounded-2xl relative overflow-hidden border border-[#d4af37]/20 shadow-2xl min-h-[160px] flex items-center justify-center">
           <div className="absolute top-0 left-0 w-1 h-full bg-[#d4af37]/40"></div>
           <h2 className="text-xl md:text-2xl font-semibold leading-relaxed text-center">
             {currentQ.text}
           </h2>
        </div>

        {/* Options */}
        <div className="grid grid-cols-1 gap-4 w-full">
          {currentQ.options.map((option, idx) => {
            let bgColor = "bg-slate-900/50";
            let borderColor = "border-slate-800";
            let textColor = "text-gray-300";

            if (state.selectedOption === idx) {
              if (idx === currentQ.correctAnswer) {
                bgColor = "bg-green-600/20";
                borderColor = "border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]";
                textColor = "text-green-400";
              } else {
                bgColor = "bg-red-600/20";
                borderColor = "border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.3)]";
                textColor = "text-red-400";
              }
            } else if (state.showFeedback && idx === currentQ.correctAnswer) {
              bgColor = "bg-green-600/20";
              borderColor = "border-green-500";
              textColor = "text-green-400";
            }

            return (
              <button
                key={idx}
                onClick={() => handleOptionClick(idx)}
                disabled={state.selectedOption !== null}
                className={`w-full group relative flex items-center p-5 rounded-xl border-2 transition-all duration-300 transform active:scale-[0.98] ${bgColor} ${borderColor} ${textColor}`}
              >
                <div className={`mr-4 w-8 h-8 rounded-lg flex items-center justify-center bg-slate-800 transition-colors font-bold ${state.selectedOption === null ? 'group-hover:bg-[#d4af37] group-hover:text-slate-900' : ''}`}>
                  {String.fromCharCode(65 + idx)}
                </div>
                <span className="flex-1 text-left font-medium">{option}</span>
              </button>
            );
          })}
        </div>
      </div>

      {/* Summary Overlay */}
      {state.isGameOver && (
        <div className="fixed inset-0 z-[100] flex flex-col items-center justify-center p-6 bg-slate-900/95 backdrop-blur-md animate-in fade-in duration-500">
          <div className="text-center w-full max-w-sm">
            <ICONS.Trophy className="w-20 h-20 text-[#d4af37] mx-auto mb-6 drop-shadow-[0_0_15px_rgba(212,175,55,0.5)]" />
            <h1 className="text-4xl font-cinzel gold-text-gradient font-bold mb-2">SESSION ENDED</h1>
            <p className="text-gray-400 mb-8 uppercase tracking-widest text-xs font-bold">Arena performance summary</p>

            <div className="grid grid-cols-2 gap-4 mb-8">
               <div className="glass-card p-4 rounded-xl border-green-500/30">
                 <div className="text-[10px] text-green-500/70 uppercase font-bold">Correct</div>
                 <div className="text-2xl font-cinzel text-green-400">{state.correctCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl border-red-500/30">
                 <div className="text-[10px] text-red-500/70 uppercase font-bold">Incorrect</div>
                 <div className="text-2xl font-cinzel text-red-400">{state.incorrectCount}</div>
               </div>
               <div className="glass-card p-4 rounded-xl col-span-2 border-[#d4af37]/30">
                 <div className="text-[10px] text-[#d4af37]/70 uppercase font-bold">Final Accumulated Score</div>
                 <div className="text-3xl font-cinzel gold-text-gradient font-bold">{state.score.toLocaleString()}</div>
               </div>
            </div>

            <button 
              onClick={() => onExit({ score: state.score, streak: state.maxStreak })}
              className="w-full py-4 gold-gradient text-slate-900 font-bold rounded-xl shadow-xl hover:scale-105 transition-all transform active:scale-95"
            >
              CONTINUE JOURNEY
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameView;
